
import { Component, Prop, h, Fragment } from '@stencil/core';

@Component({
  tag: 'kds-icon-ellipsis'
})
export class KdsIconEllipsis {

  @Prop() size: "xs" | "s" | "m" | "l" | "xl";
  @Prop() color: 'subdued' |
    'supportive' |
    'inverse' |
    'interactive' |
    'destructive' |
    'favorable' |
    'destructive-inverse' |
    'favorable-inverse' |
    'neutral-inverse' |
    'callout-inverse';

  render() {
    const paths = (
      <Fragment>
        <circle cx="4.075" cy="7.99999" r="0.7654"></circle><circle cx="8" cy="8" r="0.7654"></circle><circle cx="11.925" cy="8.00001" r="0.7654"></circle>
      </Fragment>
    )
    return (
      <kds-icon size={this.size} color={this.color} paths={paths} />
    );
  }
}